/**
 * Issue ID — 10 chars: 6 from timestamp base36 + 4 random base36
 * Sortable by creation time.
 */
export type IssueId = string;

/**
 * Comment ID — same format as IssueId: 10-char base36
 */
export type CommentId = string;

/**
 * Issue status progression: idea → todo → in-progress → done → closed
 */
export type IssueStatus = "idea" | "todo" | "in-progress" | "done" | "closed";

/**
 * Mutable properties of an issue, reconstructed by replaying events.
 */
export interface IssueProperties {
  id: IssueId;
  title: string;
  description: string;
  status: IssueStatus;
  assignee: string | null;
  parentId: IssueId | null;
  tags: string[];
  priority: 1 | 2 | 3 | 4 | 5;
}

/**
 * Full computed state of an issue, including computed fields.
 */
export interface ComputedIssue extends IssueProperties {
  createdAt: string;   // ISO 8601 — timestamp of creation event
  createdBy: string;   // author of creation event
  updatedAt: string;   // ISO 8601 — timestamp of last event
}

/**
 * Computed state of a comment.
 */
export interface ComputedComment {
  id: CommentId;
  author: string;
  content: string;
  timestamp: string;       // ISO 8601 — when the comment was created
  editedAt: string | null; // ISO 8601 — when last comment-update was applied, or null
}

import type { IssueId, CommentId, IssueProperties } from "./issue";

/**
 * Base shape for all events.
 */
export interface BaseEvent {
  timestamp: string; // ISO 8601
  author: string;    // resolved user name or "system"
}

/**
 * Creation event — marks the birth of an issue. No content.
 */
export interface CreationEvent extends BaseEvent {
  type: "creation";
}

/**
 * Update event — records changes to issue properties.
 */
export interface UpdateEvent extends BaseEvent {
  type: "update";
  content: Partial<Pick<IssueProperties, "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId">> & {
    reason?: string; // for system auto-promotion events
  };
}

/**
 * Comment event — adds a new comment.
 */
export interface CommentEvent extends BaseEvent {
  type: "comment";
  content: {
    id: CommentId;
    content: string;
  };
}

/**
 * Comment update event — edits an existing comment.
 */
export interface CommentUpdateEvent extends BaseEvent {
  type: "comment-update";
  content: {
    id: CommentId;
    content: string;
  };
}

/**
 * Comment delete event — soft-deletes a comment.
 */
export interface CommentDeleteEvent extends BaseEvent {
  type: "comment-delete";
  content: {
    id: CommentId;
  };
}

/**
 * Blockage added event — records a new dependency.
 */
export interface BlockageAddedEvent extends BaseEvent {
  type: "blockage-added";
  content: {
    blockerId: IssueId;
  };
}

/**
 * Blockage resolved event — records dependency resolution.
 */
export interface BlockageResolvedEvent extends BaseEvent {
  type: "blockage-resolved";
  content: {
    blockerId: IssueId;
  };
}

/**
 * Blockage deleted event — records dependency removal.
 */
export interface BlockageDeletedEvent extends BaseEvent {
  type: "blockage-deleted";
  content: {
    blockerId: IssueId;
  };
}

/**
 * Union of all event types.
 */
export type Event =
  | CreationEvent
  | UpdateEvent
  | CommentEvent
  | CommentUpdateEvent
  | CommentDeleteEvent
  | BlockageAddedEvent
  | BlockageResolvedEvent
  | BlockageDeletedEvent;

import type { IssueId, IssueStatus } from "./issue";

/**
 * A single entry in the index file — summary of an issue for fast lookup.
 */
export interface IndexEntry {
  id: IssueId;
  title: string;
  path: string;             // relative path to issue file
  status: IssueStatus;
  assignee: string | null;
  parentId: IssueId | null;
  tags: string[];
  priority: 1 | 2 | 3 | 4 | 5;
}

/**
 * Index file structure — two sorted arrays and a children map.
 *
 * Invariants:
 * - Both arrays are sorted by issue id (time-sortable).
 * - `open` contains entries where status !== "closed".
 * - `closed` contains entries where status === "closed".
 * - `childrenOf` keys only exist for issues that have children.
 */
export interface IndexFile {
  open: IndexEntry[];
  closed: IndexEntry[];
  childrenOf: Record<IssueId, IssueId[]>;
}

import type { IssueId } from "./issue";

/**
 * A single blockage relationship between two issues.
 */
export interface BlockageEntry {
  blockerId: IssueId;
  blockedId: IssueId;
  status: "active" | "resolved";
}

/**
 * Dependencies file — bidirectional blockage maps.
 * Both maps are always in sync. Every mutation writes both sides atomically.
 */
export interface DependenciesFile {
  blockedBy: Record<IssueId, BlockageEntry[]>; // what blocks me
  blocks: Record<IssueId, BlockageEntry[]>;    // what I block
}

/**
 * Blockage info for a specific issue (view output).
 */
export interface BlockageInfo {
  issueId: IssueId;
  blockedBy: BlockageEntry[];
  blocks: BlockageEntry[];
}

/**
 * A single registered user.
 */
export interface UserEntry {
  name: string;           // stored lowercase
  token: string;          // format: tk_ + 8 random alphanumeric chars
  registeredAt: string;   // ISO 8601
}

/**
 * Users file — list of registered users.
 */
export interface UsersFile {
  users: UserEntry[];
}

/**
 * Public user info (list output) — tokens are never included.
 */
export interface UserInfo {
  name: string;
  registeredAt: string;
}

/**
 * Configuration file stored at `.trackgentic/config.json`.
 */
export interface ConfigFile {
  auth: {
    mode: "open" | "read-only" | "strict";
    defaultUser: string;
  };
}

import type { IssueId, CommentId, IssueStatus, ComputedIssue, ComputedComment, IndexEntry, BlockageInfo, UserInfo } from "./index";

// ─── Init ───────────────────────────────────────────────────────────

export type InitResult =
  | { result: "OK"; path: string }
  | { result: "ALREADY_INITIALIZED"; path: string };

// ─── Create ─────────────────────────────────────────────────────────

export interface CreateParams {
  title: string;
  description?: string;
  assignee?: string;
  tags?: string[];              // defaults to []
  status?: IssueStatus;         // defaults to "idea"
  priority?: 1 | 2 | 3 | 4 | 5; // defaults to 3
  parentId?: IssueId | null;
  path?: string;                // defaults to issues/[id].json
  author?: string;              // resolved by auth layer if not provided
}

export type CreateResult =
  | { id: IssueId };

// ─── Update ─────────────────────────────────────────────────────────

export interface UpdateParams {
  title?: string;
  description?: string;
  status?: IssueStatus;
  assignee?: string | null;     // null to clear
  tags?: string[];
  priority?: 1 | 2 | 3 | 4 | 5;
  parentId?: IssueId | null;    // null to detach
  author?: string;
}

export type UpdateResult =
  | { result: "OK" };

// ─── List ───────────────────────────────────────────────────────────

export interface ListParams {
  status?: IssueStatus | "open"; // "open" = all except closed
  assignee?: string;
  tags?: string[];               // AND filter — issue must have ALL tags
  parentId?: IssueId | null;     // null = top-level issues only
}

export type ListResult = IndexEntry[];

// ─── View ───────────────────────────────────────────────────────────

export type ViewResult = ComputedIssue;

// ─── History ────────────────────────────────────────────────────────

import type { Event } from "./event";
export type { Event };
export type HistoryResult = Event[];

// ─── Comments ───────────────────────────────────────────────────────

export interface CommentAddParams {
  content: string;
  author?: string;
}

export type CommentAddResult =
  | { result: "OK"; commentId: CommentId };

export interface CommentUpdateParams {
  content: string;
  author?: string;
}

export type CommentUpdateResult =
  | { result: "OK" };

export interface CommentDeleteParams {
  author?: string;
}

export type CommentDeleteResult =
  | { result: "OK" };

export type CommentsListResult = ComputedComment[];

// ─── Blockages ──────────────────────────────────────────────────────

export interface BlockagesAddParams {
  blockerIds: IssueId[];
  author?: string;
}

export type BlockagesAddResult =
  | { result: "OK" };

export interface BlockagesResolveParams {
  blockerIds: IssueId[];
  author?: string;
}

export type BlockagesResolveResult =
  | { result: "OK" };

export interface BlockagesDeleteParams {
  blockerIds: IssueId[];
  author?: string;
}

export type BlockagesDeleteResult =
  | { result: "OK" };

export type BlockagesListResult = BlockageInfo;

// ─── Users ──────────────────────────────────────────────────────────

export type UsersRegisterResult =
  | { result: "OK"; name: string; token: string }
  | { result: "USER_ALREADY_EXISTS"; message: string };

export type UsersListResult = UserInfo[];

export type UsersRevokeResult =
  | { result: "OK" }
  | { result: "USER_NOT_FOUND"; message: string };

export type UsersRegenerateResult =
  | { result: "OK"; name: string; token: string }
  | { result: "USER_NOT_FOUND"; message: string }
  | { result: "INVALID_TOKEN"; message: string };

// Issue-related types
export type {
  IssueId,
  CommentId,
  IssueStatus,
  IssueProperties,
  ComputedIssue,
  ComputedComment,
} from "./issue";

// Event types
export type {
  BaseEvent,
  Event,
  CreationEvent,
  UpdateEvent,
  CommentEvent,
  CommentUpdateEvent,
  CommentDeleteEvent,
  BlockageAddedEvent,
  BlockageResolvedEvent,
  BlockageDeletedEvent,
} from "./event";

// Index file types
export type {
  IndexEntry,
  IndexFile,
} from "./index-file";

// Dependency types
export type {
  BlockageEntry,
  DependenciesFile,
  BlockageInfo,
} from "./dependency";

// User types
export type {
  UserEntry,
  UsersFile,
  UserInfo,
} from "./user";

// Config types
export type {
  ConfigFile,
} from "./config";

// API types
export type {
  InitResult,
  CreateParams,
  CreateResult,
  UpdateParams,
  UpdateResult,
  ListParams,
  ListResult,
  ViewResult,
  HistoryResult,
  CommentAddParams,
  CommentAddResult,
  CommentUpdateParams,
  CommentUpdateResult,
  CommentDeleteParams,
  CommentDeleteResult,
  CommentsListResult,
  BlockagesAddParams,
  BlockagesAddResult,
  BlockagesResolveParams,
  BlockagesResolveResult,
  BlockagesDeleteParams,
  BlockagesDeleteResult,
  BlockagesListResult,
  UsersRegisterResult,
  UsersListResult,
  UsersRevokeResult,
  UsersRegenerateResult,
} from "./api";

/**
 * Typed error class for all trackgentic operations.
 * Each error has a result code, human-readable message, and CLI exit code.
 */
export class TrackgenticError extends Error {
  constructor(
    public readonly result: string,
    public override readonly message: string,
    public readonly exitCode: number,
  ) {
    super(message);
    this.name = "TrackgenticError";
  }
}

// Error codes with their associated exit codes
export const ErrorCodes = {
  NOT_INITIALIZED: { result: "NOT_INITIALIZED", exitCode: 1 },
  ALREADY_INITIALIZED: { result: "ALREADY_INITIALIZED", exitCode: 0 },
  TOKEN_REQUIRED: { result: "TOKEN_REQUIRED", exitCode: 2 },
  INVALID_TOKEN: { result: "INVALID_TOKEN", exitCode: 3 },
  DEFAULT_USER_MISSING: { result: "DEFAULT_USER_MISSING", exitCode: 4 },
  NOT_FOUND: { result: "NOT_FOUND", exitCode: 5 },
  ISSUE_MISSING: { result: "ISSUE_MISSING", exitCode: 6 },
  COMMENT_NOT_FOUND: { result: "COMMENT_NOT_FOUND", exitCode: 7 },
  USER_ALREADY_EXISTS: { result: "USER_ALREADY_EXISTS", exitCode: 8 },
  USER_NOT_FOUND: { result: "USER_NOT_FOUND", exitCode: 9 },
  INVALID_PARAMS: { result: "INVALID_PARAMS", exitCode: 10 },
  BLOCKAGE_CYCLE: { result: "BLOCKAGE_CYCLE", exitCode: 11 },
  HIERARCHY_CONSTRAINT: { result: "HIERARCHY_CONSTRAINT", exitCode: 12 },
} as const;

import type { IssueId, CommentId } from "../types";

/**
 * Generate a unique issue ID.
 * Format: 6 chars from timestamp (base36) + 4 random chars (base36) = 10 chars total.
 * IDs are sortable by creation time.
 */
export function generateId(): IssueId {
  return Date.now().toString(36).slice(0, 6) + Math.random().toString(36).slice(-4);
}

/**
 * Generate a unique comment ID.
 * Uses the same algorithm as issue IDs.
 */
export function generateCommentId(): CommentId {
  return Date.now().toString(36).slice(0, 6) + Math.random().toString(36).slice(-4);
}

import { existsSync } from "node:fs";
import { join, resolve, dirname } from "node:path";

const TRACKGENTIC_DIR = ".trackgentic";

/**
 * Walk up from `cwd` looking for a `.trackgentic/` directory.
 * Returns the absolute path to `.trackgentic/` if found, or `null` if not found.
 * Stops at filesystem root.
 */
export function resolveTrackerDir(cwd: string): string | null {
  let current = resolve(cwd);

  while (true) {
    const candidate = join(current, TRACKGENTIC_DIR);
    if (existsSync(candidate)) {
      return candidate;
    }

    const parent = dirname(current);
    if (parent === current) {
      // Reached filesystem root
      return null;
    }
    current = parent;
  }
}

import { readFile, writeFile, rename } from "node:fs/promises";
import { dirname, join } from "node:path";
import { existsSync, mkdirSync } from "node:fs";

/**
 * Read and parse a JSON file.
 */
export async function readJSON<T>(filePath: string): Promise<T> {
  const contents = await readFile(filePath, "utf-8");
  return JSON.parse(contents) as T;
}

/**
 * Write JSON to a file atomically using write-to-temp-then-rename.
 * Creates parent directories if they don't exist.
 */
export async function atomicWriteJSON(filePath: string, data: unknown): Promise<void> {
  const dir = dirname(filePath);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  const tmpPath = join(dir, `.tmp-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
  try {
    await writeFile(tmpPath, JSON.stringify(data, null, 2) + "\n", "utf-8");
    await rename(tmpPath, filePath);
  } catch (err) {
    // Clean up temp file if rename fails
    try {
      const { unlinkSync } = await import("node:fs");
      unlinkSync(tmpPath);
    } catch {
      // Ignore cleanup errors
    }
    throw err;
  }
}

import { resolve, join } from "node:path";
import { existsSync, mkdirSync } from "node:fs";
import type { InitResult, ConfigFile, IndexFile, DependenciesFile, UsersFile } from "../types";
import { atomicWriteJSON } from "./file-io";

const TRACKGENTIC_DIR = ".trackgentic";

/**
 * Default config.json contents.
 */
const DEFAULT_CONFIG: ConfigFile = {
  auth: {
    mode: "read-only",
    defaultUser: "anonymous",
  },
};

/**
 * Default index.json contents.
 */
const DEFAULT_INDEX: IndexFile = {
  open: [],
  closed: [],
  childrenOf: {},
};

/**
 * Default dependencies.json contents.
 */
const DEFAULT_DEPENDENCIES: DependenciesFile = {
  blockedBy: {},
  blocks: {},
};

/**
 * Default users.json contents.
 */
const DEFAULT_USERS: UsersFile = {
  users: [],
};

/**
 * Tracker — the main programmatic API for trackgentic.
 *
 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
 */
export class Tracker {
  private cwd: string;

  constructor(cwd?: string) {
    this.cwd = cwd ?? process.cwd();
  }

  /**
   * Initialize a new `.trackgentic/` directory in `cwd`.
   *
   * Creates the directory with:
   * - config.json — default auth config
   * - index.json — empty open/closed arrays, empty childrenOf map
   * - dependencies.json — empty blockedBy/blocks maps
   * - users.json — empty users array
   * - issues/ — empty directory
   *
   * Idempotent: if `.trackgentic/` already exists, returns ALREADY_INITIALIZED
   * without overwriting any files.
   */
  async init(): Promise<InitResult> {
    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);

    if (existsSync(trackerDir)) {
      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
    }

    // Create the main directory
    mkdirSync(trackerDir, { recursive: true });

    // Create issues subdirectory
    mkdirSync(join(trackerDir, "issues"), { recursive: true });

    // Write initial files
    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);

    return { result: "OK", path: resolve(trackerDir) };
  }
}

/**
 * Write a JSON result to stdout.
 */
export function writeStdout(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + "\n");
}

/**
 * Write a JSON error to stderr.
 */
export function writeStderr(data: unknown): void {
  process.stderr.write(JSON.stringify(data, null, 2) + "\n");
}

import { Tracker } from "../../core/tracker";
import { TrackgenticError } from "../../core/errors";
import { writeStdout, writeStderr } from "../output";

/**
 * Handler for the `trackgentic init` command.
 * Creates a `.trackgentic/` directory in the current working directory.
 */
export async function initAction(): Promise<void> {
  try {
    const tracker = new Tracker();
    const result = await tracker.init();
    writeStdout(result);
    process.exit(0);
  } catch (err) {
    if (err instanceof TrackgenticError) {
      writeStderr({ result: err.result, message: err.message });
      process.exit(err.exitCode);
    }
    // Unexpected errors
    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
    process.exit(1);
  }
}

import { Command } from "commander";
