import { describe, test, expect, beforeEach, afterEach } from "bun:test";
import { mkdirSync, rmSync } from "node:fs";
import { join, resolve } from "node:path";
import { tmpdir } from "node:os";
import { resolveTrackerDir } from "../../src/core/resolution";

describe("resolveTrackerDir", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(tmpdir(), `trackgentic-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
    mkdirSync(testDir, { recursive: true });
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  test("finds .trackgentic/ in the current directory", () => {
    const trackerDir = join(testDir, ".trackgentic");
    mkdirSync(trackerDir);

    const result = resolveTrackerDir(testDir);
    expect(result).toBe(resolve(trackerDir));
  });

  test("finds .trackgentic/ in a parent directory", () => {
    const trackerDir = join(testDir, ".trackgentic");
    mkdirSync(trackerDir);

    const nestedDir = join(testDir, "sub", "deep");
    mkdirSync(nestedDir, { recursive: true });

    const result = resolveTrackerDir(nestedDir);
    expect(result).toBe(resolve(trackerDir));
  });

  test("returns null when no .trackgentic/ exists", () => {
    const result = resolveTrackerDir(testDir);
    expect(result).toBeNull();
  });

  test("returns correct absolute path", () => {
    const trackerDir = join(testDir, ".trackgentic");
    mkdirSync(trackerDir);

    const result = resolveTrackerDir(testDir);
    expect(result).not.toBeNull();
    expect(resolve(result!)).toBe(resolve(trackerDir));
  });
});

import { describe, test, expect, beforeEach, afterEach } from "bun:test";
import { existsSync, readFileSync, rmSync } from "node:fs";
import { join, resolve } from "node:path";
import { tmpdir } from "node:os";
import { Tracker } from "../../src/core/tracker";

describe("Tracker", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(tmpdir(), `trackgentic-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  describe("init()", () => {
    test("creates .trackgentic/ with all files and correct contents", async () => {
      const tracker = new Tracker(testDir);
      const result = await tracker.init();

      expect(result.result).toBe("OK");
      expect(result.path).toBe(resolve(join(testDir, ".trackgentic")));

      // Verify directory exists
      expect(existsSync(join(testDir, ".trackgentic"))).toBe(true);

      // Verify issues directory exists
      expect(existsSync(join(testDir, ".trackgentic", "issues"))).toBe(true);

      // Verify config.json
      const config = JSON.parse(readFileSync(join(testDir, ".trackgentic", "config.json"), "utf-8"));
      expect(config).toEqual({
        auth: {
          mode: "read-only",
          defaultUser: "anonymous",
        },
      });

      // Verify index.json
      const index = JSON.parse(readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"));
      expect(index).toEqual({
        open: [],
        closed: [],
        childrenOf: {},
      });

      // Verify dependencies.json
      const deps = JSON.parse(readFileSync(join(testDir, ".trackgentic", "dependencies.json"), "utf-8"));
      expect(deps).toEqual({
        blockedBy: {},
        blocks: {},
      });

      // Verify users.json
      const users = JSON.parse(readFileSync(join(testDir, ".trackgentic", "users.json"), "utf-8"));
      expect(users).toEqual({
        users: [],
      });
    });

    test("is idempotent — second call returns ALREADY_INITIALIZED", async () => {
      const tracker = new Tracker(testDir);

      const first = await tracker.init();
      expect(first.result).toBe("OK");

      const second = await tracker.init();
      expect(second.result).toBe("ALREADY_INITIALIZED");
      expect(second.path).toBe(resolve(join(testDir, ".trackgentic")));
    });

    test("does not overwrite existing files", async () => {
      const tracker = new Tracker(testDir);

      await tracker.init();

      // Read config to get original content
      const configPath = join(testDir, ".trackgentic", "config.json");
      const originalContent = readFileSync(configPath, "utf-8");

      // Call init again
      await tracker.init();

      // Verify config was NOT overwritten
      const contentAfter = readFileSync(configPath, "utf-8");
      expect(contentAfter).toBe(originalContent);
    });

    test("config.json has default auth config", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      const config = JSON.parse(readFileSync(join(testDir, ".trackgentic", "config.json"), "utf-8"));
      expect(config.auth.mode).toBe("read-only");
      expect(config.auth.defaultUser).toBe("anonymous");
    });

    test("index.json has empty arrays", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      const index = JSON.parse(readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"));
      expect(index.open).toEqual([]);
      expect(index.closed).toEqual([]);
      expect(index.childrenOf).toEqual({});
    });

    test("issues/ directory exists", async () => {
      const tracker = new Tracker(testDir);
      await tracker.init();

      expect(existsSync(join(testDir, ".trackgentic", "issues"))).toBe(true);
    });
  });
});

import { describe, test, expect, beforeEach, afterEach } from "bun:test";
import { rmSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { spawn } from "bun";

describe("CLI commands", () => {
  let testDir: string;

  beforeEach(() => {
    testDir = join(tmpdir(), `trackgentic-cli-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
    mkdirSync(testDir, { recursive: true });
  });

  afterEach(() => {
    rmSync(testDir, { recursive: true, force: true });
  });

  describe("init", () => {
    test("trackgentic init prints correct JSON to stdout", async () => {
      const proc = spawn({
        cmd: ["bun", "run", join(import.meta.dir, "..", "..", "src", "bin.ts"), "init"],
        cwd: testDir,
        stdout: "pipe",
        stderr: "pipe",
      });

      const stdout = await new Response(proc.stdout).text();
      const stderr = await new Response(proc.stderr).text();
      const exitCode = await proc.exited;

      expect(exitCode).toBe(0);
      expect(stderr).toBe("");

      const result = JSON.parse(stdout.trim());
      expect(result.result).toBe("OK");
      expect(result.path).toContain(".trackgentic");
    });

    test("trackgentic init when already initialized prints ALREADY_INITIALIZED", async () => {
      // First init
      const proc1 = spawn({
        cmd: ["bun", "run", join(import.meta.dir, "..", "..", "src", "bin.ts"), "init"],
        cwd: testDir,
        stdout: "pipe",
        stderr: "pipe",
      });
      await proc1.exited;

      // Second init
      const proc2 = spawn({
        cmd: ["bun", "run", join(import.meta.dir, "..", "..", "src", "bin.ts"), "init"],
        cwd: testDir,
        stdout: "pipe",
        stderr: "pipe",
      });

      const stdout = await new Response(proc2.stdout).text();
      const exitCode = await proc2.exited;

      // ALREADY_INITIALIZED is returned with exitCode 0
      // The spec says init returns InitResult which can be ALREADY_INITIALIZED
      // The CLI init command treats this as success (exitCode 0, output to stdout)
      expect(exitCode).toBe(0);

      const result = JSON.parse(stdout.trim());
      expect(result.result).toBe("ALREADY_INITIALIZED");
      expect(result.path).toContain(".trackgentic");
    });
  });
});

